mapper.select:
SELECT id, mat_code, mat_name, mat_type, stock_qty, unit
FROM materials
WHERE id = #{id}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM materials
WHERE mat_code = #{matCode}

    AND id != #{excludeId}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM materials
WHERE id = #{id}

SELECT b.id, b.product_code, b.material_id, m.mat_code, m.mat_name, m.mat_type, b.qty_per_unit, b.unit FROM bom b LEFT JOIN materials m ON m.id = b.material_id
WHERE UPPER(b.product_code) = #{productCode}
ORDER BY b.product_code ASC, m.mat_code ASC OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(*)
FROM bom

    WHERE UPPER(product_code) = #{productCode}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM bom
WHERE UPPER(product_code) = #{productCode}
  AND material_id = #{materialId}

    AND id != #{excludeId}

mapper.update:
UPDATE bom
SET product_code = #{productCode},
    material_id = #{materialId},
    qty_per_unit = #{qtyPerUnit},
    unit = #{unit}
WHERE id = #{id}
